Here's a minimal API endpoint that accepts multiple images + a description via `multipart/form-data`:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a form request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart/form-data request.");

    var form = await request.ReadFormAsync();

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images"); // matches <input name="images" />

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        // Replace with your real storage (blob, DB, etc.)
        var path = Path.Combine(Path.GetTempPath(), $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        await using var stream = File.Create(path);
        await file.CopyToAsync(stream);
        saved.Add(path);
    }

    return Results.Ok(new { description, fileCount = saved.Count, paths = saved });
})
.DisableAntiforgery()          // needed for bare form POSTs without a token
.WithName("UploadImages");

app.Run();
```

**Key points:**

- **`MaxRequestBodySize`** — Kestrel defaults to ~28 MB; set it to 50 MB explicitly.
- **`ReadFormAsync`** — gives you both the `description` text field and the `IFormFileCollection`.
- **`DisableAntiforgery`** — required in .NET 8 minimal APIs for `multipart/form-data` without an antiforgery token; remove it if you wire up tokens.
- **`GetFiles("images")`** — matches by form field name, so the client sends each file under `name="images"`.

A matching `curl` test:

```bash
curl -X POST https://localhost:5001/upload \
  -F "description=Vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
